#include <iostream>
#include <list>
using namespace std;
int main() {
    // Creazione di una lista di interi
    std::list<int> numeri;
    numeri = { 1,27,3};
    // Aggiunta di alcuni numeri alla lista
    numeri.push_back(101);
    numeri.push_back(201);
    numeri.push_back(301);
    numeri.push_back(401);
    numeri.push_back(50);
    
    list<int>::iterator it=numeri.begin();
    
    for (int numero : numeri) {
    
        if(numero%2==0){
            //CONTROLLO SE SONO DOPO END 
            if(++it==numeri.end())
                break;
            it++;
            numeri.insert(it,*it);
            break;
        }
        it++;
        
    }
    for(auto it=numeri.begin();it!=numeri.end();it++)
        cout<<*it<<" ";
    return 0;
}

